#include <iostream>
#include <string>
#include <vector>
#include <unordered_map>
#include <algorithm>

using namespace std;

// Function to find the smallest lexicographical string
string smallest_lexicographical_string(const string& P, const string& S) {
    // Create a mapping of characters to their order in P
    unordered_map<char, int> order_map;
    for (int i = 0; i < P.size(); i++) {
        order_map[P[i]] = i;
    }

    // Sort string S using the order specified in P
    vector<char> sorted_S(S.begin(), S.end());
    sort(sorted_S.begin(), sorted_S.end(), [&](char a, char b) {
        return order_map[a] < order_map[b];
    });

    // Convert the sorted vector back to a string
    return string(sorted_S.begin(), sorted_S.end());
}

int main() {
    // Number of test cases
    int T;
    cin >> T;
    cin.ignore(); // To ignore the newline character after the number input
    vector<string> results;

    // Process each test case
    for (int i = 0; i < T; i++) {
        // Read P and S for each test case
        string P, S;
        getline(cin, P);
        getline(cin, S);

        // Get the smallest lexicographical string
        string result = smallest_lexicographical_string(P, S);
        cout << result << endl;
    }

    return 0;
}

