function smallestLexicographicalString(P, S) {
    // Create a mapping of characters to their order in P
    const orderDict = {};
    for (let i = 0; i < P.length; i++) {
        orderDict[P[i]] = i;
    }

    // Sort string S using the order specified in P
    const sortedS = S.split('').sort((a, b) => orderDict[a] - orderDict[b]);

    // Convert the sorted array back to a string
    return sortedS.join('');
}

